---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

const SIDEBAR_WIDTH = "16rem"
const SIDEBAR_WIDTH_MOBILE = "18rem"
const SIDEBAR_WIDTH_ICON = "3rem"

type Props = HTMLAttributes<"div"> & {
  defaultOpen?: boolean
  open?: boolean
}

const {
  class: className,
  style,
  defaultOpen = true,
  open,
  ...props
} = Astro.props

const resolvedStyle = [
  `--sidebar-width: ${SIDEBAR_WIDTH}`,
  `--sidebar-width-mobile: ${SIDEBAR_WIDTH_MOBILE}`,
  `--sidebar-width-icon: ${SIDEBAR_WIDTH_ICON}`,
  typeof style === "string" ? style : undefined,
]
  .filter(Boolean)
  .join("; ")
---

<div
  data-slot="sidebar-wrapper"
  data-default-open={defaultOpen ? "true" : "false"}
  data-open={open === undefined ? undefined : open ? "true" : "false"}
  style={resolvedStyle}
  class={cn(
    "group/sidebar-wrapper has-data-[variant=inset]:bg-sidebar flex min-h-svh w-full",
    className
  )}
  {...props}
>
  <slot />
  <script is:inline>
    ;(() => {
      window.__fulldevSyncSidebarProvider ??= (provider, open) => {
        const state = open ? "expanded" : "collapsed"
        const sidebar = provider.querySelector(
          "[data-slot='sidebar']:not([data-mobile='true'])"
        )
        const collapsible = sidebar?.dataset.sidebarCollapsible ?? "offcanvas"

        provider.dataset.open = open ? "true" : "false"
        provider.dataset.state = state

        if (sidebar) {
          sidebar.dataset.state = collapsible === "none" ? "expanded" : state
          sidebar.dataset.collapsible =
            collapsible === "none" ? "none" : open ? "" : collapsible
        }

        provider
          .querySelectorAll("[data-sidebar='trigger'], [data-sidebar='rail']")
          .forEach((control) => {
            control.setAttribute("aria-expanded", String(open))
          })

        provider
          .querySelectorAll("[data-sidebar='menu-tooltip']")
          .forEach((tooltip) => {
            tooltip.hidden = state !== "collapsed"
          })
      }

      const provider = document.currentScript?.closest(
        "[data-slot='sidebar-wrapper']"
      )
      if (!(provider instanceof HTMLElement)) return

      const controlledOpen = provider.dataset.open
      const cookieValue = document.cookie
        .split("; ")
        .find((entry) => entry.startsWith("sidebar_state="))
        ?.slice("sidebar_state=".length)

      const isOpen =
        controlledOpen === "true" || controlledOpen === "false"
          ? controlledOpen === "true"
          : cookieValue === "true" || cookieValue === "false"
            ? cookieValue === "true"
            : provider.dataset.defaultOpen !== "false"

      provider.dataset.openMobile = "false"
      window.__fulldevSyncSidebarProvider(provider, isOpen)
    })()
  </script>
</div>

<script is:inline>
  ;(() => {
    const scrollTop = Number(sessionStorage.getItem("sidebar_scroll") || 0)

    document.querySelectorAll("[data-sidebar='content']").forEach((content) => {
      content.scrollTop = scrollTop
    })
  })()
</script>

<script is:inline>
  ;(() => {
    if (window.__fulldevSidebarInitialized) return
    window.__fulldevSidebarInitialized = true

    const SIDEBAR_COOKIE_NAME = "sidebar_state"
    const SIDEBAR_COOKIE_MAX_AGE = 60 * 60 * 24 * 7

    const toggleSidebar = (provider) => {
      if (!window.matchMedia("(min-width: 768px)").matches) {
        const openMobile = provider.dataset.openMobile !== "true"
        provider.dataset.openMobile = openMobile ? "true" : "false"
        provider
          .querySelector("[data-sidebar='sheet']")
          ?.dispatchEvent(
            new CustomEvent("dialog:set", { detail: { open: openMobile } })
          )
        return
      }

      const open = provider.dataset.open === "false"
      document.cookie = `${SIDEBAR_COOKIE_NAME}=${open}; path=/; max-age=${SIDEBAR_COOKIE_MAX_AGE}`
      window.__fulldevSyncSidebarProvider?.(provider, open)
    }

    document.addEventListener("click", (event) => {
      const control = event.target?.closest?.(
        "[data-sidebar='trigger'], [data-sidebar='rail']"
      )
      if (!control || control.matches(":disabled, [aria-disabled='true']")) {
        return
      }

      const provider = control.closest("[data-slot='sidebar-wrapper']")
      if (!provider) return

      toggleSidebar(provider)
    })

    document.addEventListener("keydown", (event) => {
      if (event.key.toLowerCase() !== "b") return
      if (!event.metaKey || event.ctrlKey || event.shiftKey || event.altKey) {
        return
      }
      if (event.defaultPrevented) return

      const target = event.target
      const isTyping =
        target instanceof HTMLElement &&
        (target.isContentEditable ||
          target.matches("input, textarea, select, [role='textbox']"))
      if (isTyping) return

      const provider = document.querySelector("[data-slot='sidebar-wrapper']")
      if (!(provider instanceof HTMLElement)) return

      event.preventDefault()
      toggleSidebar(provider)
    })

    document.addEventListener(
      "scroll",
      (event) => {
        if (event.target?.dataset?.sidebar === "content") {
          sessionStorage.setItem("sidebar_scroll", event.target.scrollTop)
        }
      },
      true
    )
  })()
</script>

---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
} from "@/components/ui/sheet"

type Props = Omit<HTMLAttributes<"div">, "dir"> & {
  side?: "left" | "right"
  variant?: "sidebar" | "floating" | "inset"
  collapsible?: "offcanvas" | "icon" | "none"
  state?: "expanded" | "collapsed"
}

const {
  class: className,
  side = "left",
  variant = "sidebar",
  collapsible = "offcanvas",
  state = "expanded",
  ...props
} = Astro.props

const desktopState = collapsible === "none" ? "expanded" : state
const desktopCollapsible = desktopState === "collapsed" ? collapsible : ""
---

{
  collapsible === "none" ? (
    <div
      data-slot="sidebar"
      data-state="expanded"
      data-collapsible="none"
      data-variant={variant}
      data-side={side}
      data-sidebar-collapsible="none"
      class={cn(
        "bg-sidebar text-sidebar-foreground flex h-full w-(--sidebar-width) flex-col",
        className
      )}
      {...props}
    >
      <slot />
    </div>
  ) : (
    <>
      <Sheet data-sidebar="sheet" defaultOpen={false}>
        <SheetContent
          side={side}
          showCloseButton={false}
          data-sidebar="sidebar"
          data-slot="sidebar"
          data-mobile="true"
          style="--sidebar-width: var(--sidebar-width-mobile);"
          class={cn(
            "bg-sidebar text-sidebar-foreground w-(--sidebar-width) p-0 md:hidden",
            className
          )}
        >
          <SheetHeader class="sr-only">
            <SheetTitle>Sidebar</SheetTitle>
            <SheetDescription>Displays the mobile sidebar.</SheetDescription>
          </SheetHeader>
          <div class="flex h-full w-full flex-col">
            <slot />
          </div>
        </SheetContent>
      </Sheet>

      <div
        data-slot="sidebar"
        data-state={desktopState}
        data-collapsible={desktopCollapsible}
        data-variant={variant}
        data-side={side}
        data-sidebar-collapsible={collapsible}
        class="group peer text-sidebar-foreground hidden md:block"
      >
        <div
          data-slot="sidebar-gap"
          class={cn(
            "relative w-(--sidebar-width) bg-transparent transition-[width] duration-200 ease-linear",
            "group-data-[collapsible=offcanvas]:w-0",
            "group-data-[side=right]:rotate-180",
            variant === "floating" || variant === "inset"
              ? "group-data-[collapsible=icon]:w-[calc(var(--sidebar-width-icon)+(--spacing(4)))]"
              : "group-data-[collapsible=icon]:w-(--sidebar-width-icon)"
          )}
        />
        <div
          data-slot="sidebar-container"
          data-side={side}
          class={cn(
            "fixed inset-y-0 z-10 hidden h-svh w-(--sidebar-width) transition-[left,right,width] duration-200 ease-linear data-[side=left]:left-0 data-[side=left]:group-data-[collapsible=offcanvas]:-left-(--sidebar-width) data-[side=right]:right-0 data-[side=right]:group-data-[collapsible=offcanvas]:-right-(--sidebar-width) md:flex",
            variant === "floating" || variant === "inset"
              ? "p-2 group-data-[collapsible=icon]:w-[calc(var(--sidebar-width-icon)+(--spacing(4))+2px)]"
              : "group-data-[collapsible=icon]:w-(--sidebar-width-icon) group-data-[side=left]:border-r group-data-[side=right]:border-l",
            className
          )}
          {...props}
        >
          <div
            data-sidebar="sidebar"
            data-slot="sidebar-inner"
            class="bg-sidebar group-data-[variant=floating]:ring-sidebar-border flex size-full flex-col group-data-[variant=floating]:rounded-lg group-data-[variant=floating]:shadow-sm group-data-[variant=floating]:ring-1"
          >
            <slot />
          </div>
        </div>
      </div>
    </>
  )
}

